function dashboardEscape(v){ return escapeHtml(String(v == null ? '' : v)); }
function dashboardSafeId(v){ return String(v == null ? '' : v).replace(/[^a-zA-Z0-9_\-\u0600-\u06FF]/g, '-'); }
function dashboardBrandLogosHtml(){
  const brand = document.querySelector('.brand-logos');
  if (brand) return brand.outerHTML;
  const img = document.querySelector('.brand-logo img, .brand-logos img, img.paper-logo, img.form-logo');
  return img ? '<div class="brand-logos"><img src="'+ img.src +'" alt=""></div>' : '<div class="brand-logos"></div>';
}
function dashboardStatusIcon(status){
  const st = String(status || '');
  if (st === 'مرفوع') return '⬆️';
  if (st === 'منجز') return '✅';
  if (st === 'منجز تلقائيًا') return '🤖';
  if (st === 'جديد') return '🕘';
  if (st === 'ناقص') return '⚠️';
  if (st === 'ملغي') return '🚫';
  return '📋';
}
function dashboardDepartmentIcon(name){
  const n = String(name || '');
  if (n.indexOf('العمارة') > -1) return '🏛️';
  if (n.indexOf('النفط') > -1) return '🛢️';
  if (n.indexOf('الطب') > -1) return '🧬';
  if (n.indexOf('الأطراف') > -1 || n.indexOf('المساند') > -1) return '🦾';
  if (n.indexOf('المدنية') > -1) return '🏗️';
  if (n.indexOf('الكهربائية') > -1 || n.indexOf('الإلكترونية') > -1) return '⚡';
  if (n.indexOf('الميكانيك') > -1) return '⚙️';
  return '🏫';
}
function dashboardCountMap(rows){
  const map = {};
  (rows || []).forEach(function(r){ map[String(r.name || '')] = Number(r.count || 0); });
  return map;
}
function dashboardTodayKeyFromValue(value){
  if (!value) return '';
  const d = typeof value === 'number' ? new Date(value) : new Date(value);
  if (isNaN(d.getTime())) return '';
  return d.getFullYear() + '-' + String(d.getMonth()+1).padStart(2,'0') + '-' + String(d.getDate()).padStart(2,'0');
}
function dashboardTodayKeyNow(){ return dashboardTodayKeyFromValue(new Date()); }
