function openDashboardLogin(){
  ensureDashboardModal();
  const modal = $('dashboardModal');
  if (!modal) return;
  modal.classList.remove('hidden');
  document.body.classList.add('dashboard-open-lock');
  document.documentElement.classList.add('dashboard-open-lock');
  if (dashboardToken && dashboardData) showDashboardApp(); else showDashboardLogin();
}
function closeDashboardModal(){
  const modal = $('dashboardModal');
  if (modal) modal.classList.add('hidden');
  document.body.classList.remove('dashboard-open-lock');
  document.documentElement.classList.remove('dashboard-open-lock');
}
function showDashboardLogin(){
  const modal = $('dashboardModal');
  if (modal) { modal.classList.add('login-mode'); modal.classList.remove('app-mode'); }
  const login = $('dashboardLoginView');
  const app = $('dashboardAppView');
  const staff = $('dashboardStaffPanel');
  if (login) { login.classList.remove('hidden'); login.style.display = 'block'; }
  if (app) { app.classList.add('hidden'); app.style.display = 'none'; }
  if (staff) staff.classList.add('hidden');
}
function showDashboardApp(){
  const modal = $('dashboardModal');
  if (modal) { modal.classList.remove('login-mode'); modal.classList.add('app-mode'); }
  const login = $('dashboardLoginView');
  const app = $('dashboardAppView');
  if (login) { login.classList.add('hidden'); login.style.display = 'none'; }
  if (app) { app.classList.remove('hidden'); app.style.display = 'block'; }
  try { renderDashboard(); }
  catch (err) {
    const warn = $('dashboardWarnings') || $('dashboardLoginMsg');
    if (warn) warn.innerHTML = '<div class="dashboard-warning">تم الدخول، لكن تعذر عرض البيانات: ' + dashboardEscape(err && err.message ? err.message : err) + '</div>';
  }
}
async function dashboardLoginSubmit(e){
  if (e) e.preventDefault();
  const msg = $('dashboardLoginMsg');
  if (msg) msg.textContent = 'جاري التحقق...';
  try{
    const username = ($('dashUsername') && $('dashUsername').value || '').trim();
    const password = ($('dashPassword') && $('dashPassword').value || '');
    const res = await runServer('dashboardLogin', { username:username, password:password });
    dashboardToken = res.token || '';
    dashboardStaff = res.staff || null;
    dashboardData = res.data || null;
    if (!dashboardToken) throw new Error('تم قبول البيانات لكن لم يصل رمز الدخول من الخادم. أعد النشر ثم جرّب.');
    if (!dashboardData) {
      const fresh = await runServer('dashboardGetData', { token: dashboardToken });
      dashboardData = fresh.data || null;
    }
    if (!dashboardData) throw new Error('تم الدخول لكن بيانات لوحة المتابعة لم تصل من الخادم.');
    if (msg) msg.textContent = '';
    dashboardActiveQuickFilter = { type:'all', value:'' };
    showDashboardApp();
  }catch(err){
    if (msg) msg.textContent = err && err.message ? err.message : 'تعذر الدخول.';
  }
}
async function dashboardRefresh(){
  if (!dashboardToken) return;
  const btn = $('dashboardRefreshBtn');
  if (btn) btn.disabled = true;
  try{
    const res = await runServer('dashboardGetData', { token: dashboardToken });
    dashboardData = res.data;
    renderDashboard();
  }catch(err){ alert(err.message || 'تعذر تحديث البيانات.'); }
  finally{ if (btn) btn.disabled = false; }
}
function dashboardLogout(){ dashboardToken=''; dashboardStaff=null; dashboardData=null; dashboardActiveQuickFilter = { type:'all', value:'' }; showDashboardLogin(); }
function dashboardStatCard(options){
  const active = dashboardActiveQuickFilter.type === options.type && String(dashboardActiveQuickFilter.value || '') === String(options.value || '');
  return `<button type="button" class="dashboard-stat-card dash-click-card tone-${dashboardEscape(options.tone || 'blue')} ${active ? 'is-active' : ''}" data-filter-type="${dashboardEscape(options.type)}" data-filter-value="${dashboardEscape(options.value || '')}">
    <span class="dash-card-icon" aria-hidden="true">${dashboardEscape(options.icon || '📊')}</span>
    <strong>${dashboardEscape(options.valueText)}</strong>
    <em>${dashboardEscape(options.title)}</em>
  </button>`;
}
function renderDashboard(){
  if (!dashboardData) return;
  const s = dashboardData.stats || {};
  if ($('dashboardUserBox')) $('dashboardUserBox').innerHTML = `<span>${dashboardEscape(dashboardStaff && dashboardStaff.role === 'admin' ? 'مدير' : 'موظف')}</span><strong>${dashboardEscape(dashboardStaff && dashboardStaff.name || '')}</strong>`;
  if ($('dashboardStaffBtn')) $('dashboardStaffBtn').style.display = dashboardStaff && dashboardStaff.role === 'admin' ? '' : 'none';
  $('dashboardStats').innerHTML = [
    dashboardStatCard({title:'كل الطلبات', valueText:s.total || 0, icon:'📋', type:'all', value:'', tone:'blue'}),
    dashboardStatCard({title:'طلبات اليوم', valueText:s.today || 0, icon:'📅', type:'today', value:'today', tone:'cyan'}),
    dashboardStatCard({title:'بانتظار الرفع', valueText:s.newCount || 0, icon:'🕘', type:'status', value:'جديد', tone:'amber'}),
    dashboardStatCard({title:'مرفوعة', valueText:s.uploaded || 0, icon:'⬆️', type:'status', value:'مرفوع', tone:'violet'}),
    dashboardStatCard({title:'منجزة', valueText:s.completed || 0, icon:'✅', type:'status', value:'منجز', tone:'green'}),
    dashboardStatCard({title:'تلقائي', valueText:s.autoCompleted || 0, icon:'🤖', type:'status', value:'منجز تلقائيًا', tone:'sky'})
  ].join('');
  dashboardFillSelect('dashStatusFilter', (s.byStatus || []).map(function(x){ return x.name; }), 'كل الحالات');
  dashboardFillSelect('dashFormFilter', (s.byForm || []).map(function(x){ return x.name; }), 'كل الاستمارات');
  dashboardFillSelect('dashDeptFilter', (typeof departments !== 'undefined' ? departments : (s.byDepartment || []).map(function(x){ return x.name; })), 'كل الأقسام');
  renderDepartmentCards('dashByDepartment', s.byDepartment || []);
  renderMiniList('dashByForm', s.byForm || []);
  $('dashboardWarnings').innerHTML = s.unmatchedUploads ? `<div class="dashboard-warning">لديك ${dashboardEscape(s.unmatchedUploads)} ملف مرفوع بلا رقم طلب. تم احتسابها ضمن المرفوعات، لكن زر منجز يحتاج أن يكون الملف مربوطًا برقم الطلب الأصلي.</div>` : '';
  dashboardApplyFilters();
  qsa('.dash-click-card').forEach(function(btn){ btn.addEventListener('click', function(){ dashboardActivateCard(btn.dataset.filterType, btn.dataset.filterValue || ''); dashboardScrollToResults(); }); });
  qsa('.dept-card').forEach(function(btn){ btn.addEventListener('click', function(){ dashboardActivateCard('department', btn.dataset.dept || ''); dashboardScrollToResults(); }); });
}
function dashboardFillSelect(id, values, first){
  const el = $(id); if (!el) return;
  const old = el.value;
  const clean = [];
  (values || []).forEach(function(v){ if (v && clean.indexOf(v) === -1) clean.push(v); });
  el.innerHTML = `<option value="">${first}</option>` + clean.map(function(v){ return `<option value="${dashboardEscape(v)}">${dashboardEscape(v)}</option>`; }).join('');
  if (clean.indexOf(old) > -1 || old === '') el.value = old;
}
function renderDepartmentCards(id, rows){
  const el = $(id); if (!el) return;
  const map = dashboardCountMap(rows || []);
  const names = (typeof departments !== 'undefined' && departments && departments.length) ? departments.slice(0, 7) : Object.keys(map).slice(0, 7);
  el.innerHTML = names.map(function(name, idx){
    const count = map[name] || 0;
    const active = dashboardActiveQuickFilter.type === 'department' && dashboardActiveQuickFilter.value === name;
    return `<button type="button" class="dept-card dash-click-card dept-tone-${idx%7} ${active ? 'is-active' : ''}" data-filter-type="department" data-filter-value="${dashboardEscape(name)}" data-dept="${dashboardEscape(name)}">
      <span class="dash-card-icon" aria-hidden="true">${dashboardEscape(dashboardDepartmentIcon(name))}</span>
      <strong>${dashboardEscape(count)}</strong>
      <em>${dashboardEscape(name)}</em>
    </button>`;
  }).join('') || '<p class="muted">لا توجد أقسام.</p>';
}
function renderMiniList(id, rows){
  const el = $(id); if (!el) return;
  el.innerHTML = (rows || []).slice(0, 12).map(function(r){
    const name = r.name || '';
    return `<button type="button" class="form-filter-chip" data-form="${dashboardEscape(name)}"><span>${dashboardEscape(name || 'غير محدد')}</span><strong>${dashboardEscape(r.count || 0)}</strong></button>`;
  }).join('') || '<p class="muted">لا توجد بيانات.</p>';
  qsa('.form-filter-chip').forEach(function(btn){ btn.addEventListener('click', function(){ dashboardActivateCard('form', btn.dataset.form || ''); dashboardScrollToResults(); }); });
}
function dashboardActivateCard(type, value){
  dashboardActiveQuickFilter = { type:type || 'all', value:value || '' };
  if ($('dashSearch')) $('dashSearch').value = '';
  if ($('dashStatusFilter')) $('dashStatusFilter').value = '';
  if ($('dashFormFilter')) $('dashFormFilter').value = '';
  if ($('dashDeptFilter')) $('dashDeptFilter').value = '';
  if (type === 'status' && $('dashStatusFilter')) $('dashStatusFilter').value = value || '';
  if (type === 'department' && $('dashDeptFilter')) $('dashDeptFilter').value = value || '';
  if (type === 'form' && $('dashFormFilter')) $('dashFormFilter').value = value || '';
  renderDashboard();
}
function dashboardResultLabel(){
  const type = dashboardActiveQuickFilter.type;
  const value = dashboardActiveQuickFilter.value || '';
  if (type === 'status' && value) return 'عرض حالة: ' + value;
  if (type === 'department' && value) return 'عرض قسم: ' + value;
  if (type === 'form' && value) return 'عرض استمارة: ' + value;
  if (type === 'today') return 'طلبات اليوم';
  return 'كل الطلبات';
}
function dashboardApplyFilters(){
  if (!dashboardData) return;
  const q = ($('dashSearch') && $('dashSearch').value || '').trim();
  const status = $('dashStatusFilter') ? $('dashStatusFilter').value : '';
  const form = $('dashFormFilter') ? $('dashFormFilter').value : '';
  const dept = $('dashDeptFilter') ? $('dashDeptFilter').value : '';
  const todayKey = dashboardTodayKeyNow();
  const useToday = dashboardActiveQuickFilter.type === 'today';
  const rows = (dashboardData.requests || []).filter(function(r){
    const hay = [r.requestNo,r.studentName,r.phone,r.department,r.formTitle,r.stage,r.studyType].join(' ');
    const rowDateKey = dashboardTodayKeyFromValue(r.rawTimestampMs || r.rawTimestamp || r.timestamp);
    return (!q || hay.indexOf(q) > -1) && (!status || r.status === status) && (!form || r.formTitle === form) && (!dept || r.department === dept) && (!useToday || rowDateKey === todayKey);
  });
  if ($('dashboardResultTitle')) $('dashboardResultTitle').textContent = dashboardResultLabel() + ' (' + rows.length + ')';
  $('dashboardRows').innerHTML = rows.map(renderDashboardRow).join('') || '<tr><td colspan="7" class="dashboard-empty">لا توجد طلبات مطابقة.</td></tr>';
  qsa('.dash-done-btn').forEach(function(btn){ btn.addEventListener('click', function(){ dashboardMarkDone(btn.dataset.req); }); });
}
function statusBadge(status){
  const st = String(status || 'جديد');
  let cls = 'new';
  if (st === 'مرفوع') cls = 'uploaded';
  if (st === 'منجز') cls = 'done';
  if (st === 'منجز تلقائيًا') cls = 'auto';
  if (st === 'ناقص') cls = 'missing';
  if (st === 'ملغي') cls = 'cancelled';
  return `<span class="dashboard-status ${cls}">${dashboardEscape(dashboardStatusIcon(st))} ${dashboardEscape(st)}</span>`;
}
function renderDashboardRow(r){
  const files = Number(r.uploadedFilesCount || 0);
  const fileHtml = files ? `<a href="${dashboardEscape(r.lastUploadUrl)}" target="_blank" rel="noopener">فتح (${dashboardEscape(files)})</a>` : '<span class="muted">لا يوجد</span>';
  const canDone = r.status === 'مرفوع' && r.requestNo;
  const action = canDone ? `<button type="button" class="btn primary tiny dash-done-btn" data-req="${dashboardEscape(r.requestNo)}">✅ منجز</button>` : (r.status === 'منجز' ? '<span class="done-inline">تم الإنجاز</span>' : '<span class="muted">—</span>');
  const phone = r.phone ? `<a class="phone-link" href="tel:${dashboardEscape(r.phone)}">${dashboardEscape(r.phone)}</a>` : '<span class="muted">لا يوجد هاتف</span>';
  return `<tr>
    <td><strong>${dashboardEscape(r.studentName || 'بدون اسم')}</strong><small>${phone}</small></td>
    <td><strong class="request-no">${dashboardEscape(r.requestNo || 'غير مربوط')}</strong><small>${dashboardEscape(r.timestamp || '')}</small></td>
    <td>${dashboardEscape(r.department || 'غير محدد')}<small>${dashboardEscape([r.stage,r.studyType].filter(Boolean).join(' · '))}</small></td>
    <td>${dashboardEscape(r.formTitle || 'ملف مرفوع')}<small>${dashboardEscape(r.formCode || '')}</small></td>
    <td>${statusBadge(r.status)}</td>
    <td>${fileHtml}</td>
    <td>${action}</td>
  </tr>`;
}
async function dashboardMarkDone(requestNo){
  if (!requestNo) return;
  const note = prompt('ملاحظة الإنجاز اختيارية:', 'تمت إجراءات التسجيل');
  if (note === null) return;
  try{
    const res = await runServer('dashboardMarkDone', { token:dashboardToken, requestNo:requestNo, note:note });
    dashboardData = res.data;
    dashboardActiveQuickFilter = { type:'status', value:'مرفوع' };
    renderDashboard();
  }catch(err){ alert(err.message || 'تعذر تحديث الحالة.'); }
}
function clearStaffForm(){
  ['staffName','staffEmail','staffUsername','staffPassword'].forEach(function(id){ if($(id)) $(id).value=''; });
  if ($('staffRole')) $('staffRole').value = 'staff';
  if ($('staffActive')) $('staffActive').value = 'true';
  if ($('dashboardStaffMsg')) $('dashboardStaffMsg').textContent = '';
}
async function openDashboardStaffPanel(){
  if (!dashboardToken || !(dashboardStaff && dashboardStaff.role === 'admin')) return;
  $('dashboardStaffPanel').classList.remove('hidden');
  await dashboardLoadStaff();
}
async function dashboardLoadStaff(){
  try{
    const res = await runServer('dashboardListStaff', { token:dashboardToken });
    $('dashboardStaffList').innerHTML = (res.staff || []).map(function(s){
      return `<div class="staff-row clean-staff-row">
        <div><strong>${dashboardEscape(s.name)}</strong><span>${dashboardEscape(s.email)} · ${dashboardEscape(s.username)} · ${dashboardEscape(s.role === 'admin' ? 'مدير' : 'موظف')} · ${s.active ? 'فعال' : 'موقوف'}</span></div>
        <div class="staff-actions">
          <button type="button" class="btn ghost tiny dash-staff-edit" data-name="${dashboardEscape(s.name)}" data-email="${dashboardEscape(s.email)}" data-user="${dashboardEscape(s.username)}" data-pass="${dashboardEscape(s.password || '')}" data-role="${dashboardEscape(s.role)}" data-active="${s.active ? 'true':'false'}">تعديل</button>
          <button type="button" class="btn ghost tiny dash-staff-toggle" data-user="${dashboardEscape(s.username)}" data-active="${s.active ? '0':'1'}">${s.active ? 'إيقاف':'تفعيل'}</button>
        </div>
      </div>`;
    }).join('') || '<p>لا يوجد موظفون.</p>';
    qsa('.dash-staff-edit').forEach(function(btn){ btn.addEventListener('click', function(){
      $('staffName').value = btn.dataset.name || '';
      $('staffEmail').value = btn.dataset.email || '';
      $('staffUsername').value = btn.dataset.user || '';
      $('staffPassword').value = btn.dataset.pass || '';
      $('staffRole').value = btn.dataset.role === 'admin' ? 'admin' : 'staff';
      $('staffActive').value = btn.dataset.active === 'false' ? 'false' : 'true';
      $('dashboardStaffMsg').textContent = 'عدّل البيانات ثم اضغط حفظ / تحديث.';
    }); });
    qsa('.dash-staff-toggle').forEach(function(btn){ btn.addEventListener('click', async function(){
      await runServer('dashboardToggleStaff', { token:dashboardToken, username:btn.dataset.user, active:btn.dataset.active === '1' });
      await dashboardLoadStaff();
    }); });
  }catch(err){ $('dashboardStaffMsg').textContent = err.message || 'تعذر تحميل الموظفين.'; }
}
async function dashboardAddStaffSubmit(e){
  e.preventDefault();
  try{
    const staff = { name:$('staffName').value.trim(), email:$('staffEmail').value.trim(), username:$('staffUsername').value.trim(), password:$('staffPassword').value, role:$('staffRole').value, active:$('staffActive').value === 'true' };
    await runServer('dashboardAddStaff', { token:dashboardToken, staff:staff });
    clearStaffForm();
    $('dashboardStaffMsg').textContent = 'تم حفظ بيانات الموظف.';
    await dashboardLoadStaff();
  }catch(err){ $('dashboardStaffMsg').textContent = err.message || 'تعذر حفظ بيانات الموظف.'; }
}


/* =======================
   لوحة المتابعة v8 - بطاقات فقط + جدول عند الضغط + تحديث تلقائي + موبايل
   ======================= */
let dashboardAutoRefreshTimer = null;
let dashboardSilentRefresh = false;

function dashboardStopAutoRefresh(){
  if (dashboardAutoRefreshTimer) clearInterval(dashboardAutoRefreshTimer);
  dashboardAutoRefreshTimer = null;
}
function dashboardStartAutoRefresh(){
  dashboardStopAutoRefresh();
  dashboardAutoRefreshTimer = setInterval(function(){ dashboardRefresh(true); }, 25000);
}
function dashboardSetRefreshText(text){
  const el = $('dashboardRefreshState');
  if (el) el.textContent = text || '';
}
function ensureDashboardModal(){
  const old = $('dashboardModal');
  if (old) old.remove();
  const modal = document.createElement('div');
  modal.id = 'dashboardModal';
  modal.className = 'dashboard-modal hidden dashboard-pro-v8 login-mode';
  modal.innerHTML = `
    <div class="dashboard-shell" dir="rtl">
      <button type="button" class="dashboard-close pro-close" id="dashboardCloseBtn" aria-label="إغلاق">×</button>
      <div id="dashboardLoginView" class="dashboard-login-view">
        <form id="dashboardLoginForm" class="dashboard-login-card pro-login-card" autocomplete="off">
          <div class="pro-login-brand">
            ${dashboardBrandLogosHtml()}
            <span>وزارة التعليم العالي والبحث العلمي</span>
            <h3>البوابة الالكترونية للطلبات الطلابية</h3>
            <p>كلية الهندسة · جامعة كربلاء</p>
          </div>
          <div class="pro-login-title">دخول موظفي التسجيل</div>
          <label class="pro-field"><span>اسم المستخدم</span><input id="dashUsername" autocomplete="username" inputmode="text" required></label>
          <label class="pro-field"><span>كلمة المرور</span><input id="dashPassword" type="password" autocomplete="current-password" required></label>
          <button class="btn primary pro-login-btn" type="submit">دخول لوحة المتابعة</button>
          <div id="dashboardLoginMsg" class="dashboard-msg pro-msg"></div>
        </form>
      </div>
      <div id="dashboardAppView" class="dashboard-app-view hidden">
        <div class="pro-head">
          <div class="pro-head-brand">
            ${dashboardBrandLogosHtml()}
            <div><span>لوحة المتابعة</span><h2>بطاقات متابعة الطلبات</h2><p>كلية الهندسة · جامعة كربلاء</p></div>
          </div>
          <div class="pro-actions">
            <div class="dashboard-user" id="dashboardUserBox"></div>
            <span class="refresh-state" id="dashboardRefreshState"></span>
            <button type="button" class="btn ghost tiny" id="dashboardRefreshBtn">تحديث من الشيت/الدرايف</button>
            <button type="button" class="btn ghost tiny" id="dashboardStaffBtn">إدارة الموظفين</button>
            <button type="button" class="btn ghost tiny" id="dashboardLogoutBtn">خروج</button>
          </div>
        </div>
        <section class="dash-section cards-only-section">
          <div class="dash-section-title"><span>الإحصائيات العامة</span></div>
          <div id="dashboardStats" class="dashboard-stats compact-click-cards"></div>
        </section>
        <section class="dash-section cards-only-section">
          <div class="dash-section-title"><span>الأقسام السبعة</span></div>
          <div id="dashByDepartment" class="dash-dept-cards compact-click-cards"></div>
        </section>
        <div id="dashboardHomeHint" class="dashboard-home-hint"><span>Designed and Developed by</span><strong>Aymen Mohammed Jebur</strong></div>
        <section class="pro-table-card hidden" id="dashboardResultsAnchor">
          <div class="dash-results-head">
            <div><span>الجدول المقصود</span><strong id="dashboardResultTitle">كل الطلبات</strong></div>
            <button type="button" class="btn ghost tiny" id="dashboardClearFiltersBtn">رجوع للبطاقات</button>
          </div>
          <div class="pro-filters">
            <input id="dashSearch" placeholder="بحث: الاسم، الهاتف، القسم، الاستمارة">
            <select id="dashStatusFilter"><option value="">كل الحالات</option></select>
            <select id="dashFormFilter"><option value="">كل الاستمارات</option></select>
            <select id="dashDeptFilter"><option value="">كل الأقسام</option></select>
          </div>
          <div id="dashboardWarnings"></div>
          <div class="pro-table-wrap">
            <table class="dashboard-table pro-dashboard-table">
              <thead><tr>
                <th>الطالب</th><th>رقم الهاتف</th><th>القسم</th><th>المرحلة</th><th>الدراسة</th><th>الاستمارة</th><th>الحالة</th><th>ملفات الدرايف</th><th>الإجراء</th>
              </tr></thead>
              <tbody id="dashboardRows"></tbody>
            </table>
          </div>
        </section>
        <section class="dashboard-staff-panel pro-staff-panel hidden" id="dashboardStaffPanel">
          <div class="dashboard-panel-head"><h3>إدارة الموظفين وكلمات المرور</h3><button type="button" id="dashboardStaffClose" class="dashboard-close-small">×</button></div>
          <form id="dashboardAddStaffForm" class="dashboard-staff-form pro-staff-form">
            <input type="hidden" id="staffOriginalUsername">
            <label><span>الاسم</span><input id="staffName" required></label>
            <label><span>الإيميل</span><input id="staffEmail" type="email" required></label>
            <label><span>اليوزر</span><input id="staffUsername" required></label>
            <label><span>كلمة المرور</span><input id="staffPassword" type="password" placeholder="للجديد مطلوبة، وللتعديل اتركها فارغة إذا لا تريد تغييرها"></label>
            <label><span>الصلاحية</span><select id="staffRole"><option value="staff">موظف</option><option value="admin">مدير</option></select></label>
            <label><span>الحالة</span><select id="staffActive"><option value="true">فعال</option><option value="false">موقوف</option></select></label>
            <button class="btn primary" id="staffSaveBtn" type="submit">حفظ</button>
            <button class="btn ghost" id="staffClearBtn" type="button">جديد</button>
          </form>
          <div id="dashboardStaffMsg" class="dashboard-msg"></div>
          <div id="dashboardStaffList" class="dashboard-staff-list pro-staff-list"></div>
        </section>
      </div>
    </div>`;
  document.body.appendChild(modal);
  $('dashboardCloseBtn').addEventListener('click', closeDashboardModal);
  $('dashboardLoginForm').addEventListener('submit', dashboardLoginSubmit);
  $('dashboardRefreshBtn').addEventListener('click', function(){ dashboardRefresh(false); });
  $('dashboardLogoutBtn').addEventListener('click', dashboardLogout);
  $('dashboardStaffBtn').addEventListener('click', openDashboardStaffPanel);
  $('dashboardStaffClose').addEventListener('click', function(){ $('dashboardStaffPanel').classList.add('hidden'); });
  $('dashboardAddStaffForm').addEventListener('submit', dashboardAddStaffSubmit);
  $('staffClearBtn').addEventListener('click', clearStaffForm);
  $('dashboardClearFiltersBtn').addEventListener('click', function(){ dashboardActivateCard('home',''); });
  ['dashSearch','dashStatusFilter','dashFormFilter','dashDeptFilter'].forEach(function(id){
    const el = $(id);
    if (!el) return;
    el.addEventListener('input', function(){ dashboardActiveQuickFilter = { type:'manual', value:'' }; dashboardApplyFilters(); });
    el.addEventListener('change', function(){ dashboardActiveQuickFilter = { type:'manual', value:'' }; dashboardApplyFilters(); });
  });
}
function openDashboardLogin(){
  ensureDashboardModal();
  const modal = $('dashboardModal');
  if (!modal) return;
  modal.classList.remove('hidden');
  document.body.classList.add('dashboard-open-lock');
  document.documentElement.classList.add('dashboard-open-lock');
  if (dashboardToken && dashboardData) showDashboardApp(); else showDashboardLogin();
}
function closeDashboardModal(){
  dashboardStopAutoRefresh();
  const modal = $('dashboardModal');
  if (modal) modal.classList.add('hidden');
  document.body.classList.remove('dashboard-open-lock');
  document.documentElement.classList.remove('dashboard-open-lock');
}
function showDashboardLogin(){
  dashboardStopAutoRefresh();
  const modal = $('dashboardModal');
  if (modal) { modal.classList.add('login-mode'); modal.classList.remove('app-mode'); }
  const login = $('dashboardLoginView');
  const app = $('dashboardAppView');
  const staff = $('dashboardStaffPanel');
  if (login) { login.classList.remove('hidden'); login.style.display = 'block'; }
  if (app) { app.classList.add('hidden'); app.style.display = 'none'; }
  if (staff) staff.classList.add('hidden');
}
function showDashboardApp(){
  const modal = $('dashboardModal');
  if (modal) { modal.classList.remove('login-mode'); modal.classList.add('app-mode'); }
  const login = $('dashboardLoginView');
  const app = $('dashboardAppView');
  if (login) { login.classList.add('hidden'); login.style.display = 'none'; }
  if (app) { app.classList.remove('hidden'); app.style.display = 'block'; }
  try { renderDashboard(); dashboardStartAutoRefresh(); }
  catch (err) {
    const warn = $('dashboardWarnings') || $('dashboardLoginMsg');
    if (warn) warn.innerHTML = '<div class="dashboard-warning">تم الدخول، لكن تعذر عرض البيانات: ' + dashboardEscape(err && err.message ? err.message : err) + '</div>';
  }
}
async function dashboardLoginSubmit(e){
  if (e) e.preventDefault();
  const msg = $('dashboardLoginMsg');
  if (msg) msg.textContent = 'جاري التحقق...';
  try{
    const username = ($('dashUsername') && $('dashUsername').value || '').trim();
    const password = ($('dashPassword') && $('dashPassword').value || '');
    const res = await runServer('dashboardLogin', { username:username, password:password });
    dashboardToken = res.token || '';
    dashboardStaff = res.staff || null;
    dashboardData = res.data || null;
    if (!dashboardToken) throw new Error('تم قبول البيانات لكن لم يصل رمز الدخول من الخادم. أعد النشر ثم جرّب.');
    if (!dashboardData) {
      const fresh = await runServer('dashboardGetData', { token: dashboardToken });
      dashboardData = fresh.data || null;
    }
    if (!dashboardData) throw new Error('تم الدخول لكن بيانات لوحة المتابعة لم تصل من الخادم.');
    if (msg) msg.textContent = '';
    dashboardActiveQuickFilter = { type:'home', value:'' };
    showDashboardApp();
  }catch(err){
    if (msg) msg.textContent = err && err.message ? err.message : 'تعذر الدخول.';
  }
}
async function dashboardRefresh(silent){
  if (!dashboardToken || dashboardSilentRefresh) return;
  dashboardSilentRefresh = true;
  const btn = $('dashboardRefreshBtn');
  if (btn && !silent) btn.disabled = true;
  dashboardSetRefreshText(silent ? 'تحديث تلقائي...' : 'جاري التحديث...');
  try{
    const res = await runServer('dashboardGetData', { token: dashboardToken });
    dashboardData = res.data;
    renderDashboard();
    dashboardSetRefreshText('آخر تحديث: ' + new Date().toLocaleTimeString('ar-IQ'));
  }catch(err){
    dashboardSetRefreshText('تعذر التحديث');
    if (!silent) alert(err.message || 'تعذر تحديث البيانات.');
  } finally {
    dashboardSilentRefresh = false;
    if (btn) btn.disabled = false;
  }
}
function dashboardLogout(){
  dashboardStopAutoRefresh();
  dashboardToken=''; dashboardStaff=null; dashboardData=null; dashboardActiveQuickFilter = { type:'home', value:'' };
  showDashboardLogin();
}
function dashboardStatCard(options){
  const active = dashboardActiveQuickFilter.type === options.type && String(dashboardActiveQuickFilter.value || '') === String(options.value || '');
  return `<button type="button" class="dashboard-stat-card dash-click-card ${options.tone || ''} ${active ? 'is-active' : ''}" data-filter-type="${dashboardEscape(options.type || 'all')}" data-filter-value="${dashboardEscape(options.value || '')}">
    <span class="dash-card-icon" aria-hidden="true">${dashboardEscape(options.icon || '📋')}</span>
    <strong>${dashboardEscape(options.count || 0)}</strong>
    <em>${dashboardEscape(options.label || '')}</em>
  </button>`;
}
function renderDashboard(){
  if (!dashboardData) return;
  const s = dashboardData.stats || {};
  if ($('dashboardUserBox')) $('dashboardUserBox').innerHTML = `<strong>${dashboardEscape(dashboardStaff && dashboardStaff.name || 'موظف')}</strong><span>${dashboardEscape(dashboardStaff && dashboardStaff.role === 'admin' ? 'مدير' : 'موظف')}</span>`;
  if ($('dashboardStaffBtn')) $('dashboardStaffBtn').style.display = dashboardStaff && dashboardStaff.role === 'admin' ? '' : 'none';
  const stats = [
    { label:'كل الطلبات', count:s.total || 0, icon:'📋', type:'all', tone:'tone-blue' },
    { label:'جديدة', count:s.newCount || 0, icon:'🕘', type:'status', value:'جديد', tone:'tone-slate' },
    { label:'مرفوعة', count:s.uploaded || 0, icon:'⬆️', type:'status', value:'مرفوع', tone:'tone-amber' },
    { label:'منجزة', count:s.completed || 0, icon:'✅', type:'status', value:'منجز', tone:'tone-green' },
    { label:'فحص ومعالجة تلقائي', count:s.autoCompleted || 0, icon:'🩺', type:'status', value:'منجز تلقائيًا', tone:'tone-cyan' },
    { label:'ملفات الدرايف', count:s.uploadedTotal || 0, icon:'📁', type:'hasFiles', tone:'tone-violet' },
    { label:'غير مربوطة', count:s.unmatchedUploads || 0, icon:'🔗', type:'unmatched', tone:'tone-red' },
    { label:'طلبات اليوم', count:s.today || 0, icon:'📅', type:'today', tone:'tone-teal' }
  ];
  if ($('dashboardStats')) $('dashboardStats').innerHTML = stats.map(dashboardStatCard).join('');
  renderDepartmentCards('dashByDepartment', s.byDepartment || []);
  dashboardFillSelect('dashStatusFilter', (s.byStatus || []).map(function(x){ return x.name; }), 'كل الحالات');
  dashboardFillSelect('dashFormFilter', (s.byForm || []).map(function(x){ return x.name; }), 'كل الاستمارات');
  dashboardFillSelect('dashDeptFilter', (typeof departments !== 'undefined' ? departments : (s.byDepartment || []).map(function(x){ return x.name; })), 'كل الأقسام');
  qsa('#dashboardModal .dash-click-card').forEach(function(btn){
    btn.addEventListener('click', function(){ dashboardActivateCard(btn.dataset.filterType || 'all', btn.dataset.filterValue || ''); });
  });
  const results = $('dashboardResultsAnchor');
  const hint = $('dashboardHomeHint');
  if (dashboardActiveQuickFilter.type === 'home') {
    if (results) results.classList.add('hidden');
    if (hint) hint.classList.remove('hidden');
  } else {
    if (results) results.classList.remove('hidden');
    if (hint) hint.classList.add('hidden');
    dashboardApplyFilters();
  }
}
function renderDepartmentCards(id, rows){
  const el = $(id); if (!el) return;
  const map = dashboardCountMap(rows || []);
  const names = (typeof departments !== 'undefined' && departments && departments.length) ? departments.slice(0, 7) : Object.keys(map).slice(0, 7);
  el.innerHTML = names.map(function(name, idx){
    const count = map[name] || 0;
    const active = dashboardActiveQuickFilter.type === 'department' && dashboardActiveQuickFilter.value === name;
    return `<button type="button" class="dept-card dash-click-card dept-tone-${idx%7} ${active ? 'is-active' : ''}" data-filter-type="department" data-filter-value="${dashboardEscape(name)}" data-dept="${dashboardEscape(name)}">
      <span class="dash-card-icon" aria-hidden="true">${dashboardEscape(dashboardDepartmentIcon(name))}</span>
      <strong>${dashboardEscape(count)}</strong>
      <em>${dashboardEscape(name)}</em>
    </button>`;
  }).join('') || '<p class="muted">لا توجد أقسام.</p>';
}
function dashboardActivateCard(type, value){
  dashboardActiveQuickFilter = { type:type || 'all', value:value || '' };
  if ($('dashSearch')) $('dashSearch').value = '';
  if ($('dashStatusFilter')) $('dashStatusFilter').value = '';
  if ($('dashFormFilter')) $('dashFormFilter').value = '';
  if ($('dashDeptFilter')) $('dashDeptFilter').value = '';
  if (type === 'status' && $('dashStatusFilter')) $('dashStatusFilter').value = value || '';
  if (type === 'department' && $('dashDeptFilter')) $('dashDeptFilter').value = value || '';
  if (type === 'form' && $('dashFormFilter')) $('dashFormFilter').value = value || '';
  renderDashboard();
  if (type !== 'home') dashboardScrollToResults();
}
function dashboardResultLabel(){
  const type = dashboardActiveQuickFilter.type;
  const value = dashboardActiveQuickFilter.value || '';
  if (type === 'status' && value) return 'عرض حالة: ' + value;
  if (type === 'department' && value) return 'عرض قسم: ' + value;
  if (type === 'form' && value) return 'عرض استمارة: ' + value;
  if (type === 'today') return 'طلبات اليوم';
  if (type === 'hasFiles') return 'طلبات لها ملفات في الدرايف';
  if (type === 'unmatched') return 'الملفات غير المربوطة';
  return 'كل الطلبات';
}
function dashboardApplyFilters(){
  if (!dashboardData || !$('dashboardRows')) return;
  const q = ($('dashSearch') && $('dashSearch').value || '').trim();
  const status = $('dashStatusFilter') ? $('dashStatusFilter').value : '';
  const form = $('dashFormFilter') ? $('dashFormFilter').value : '';
  const dept = $('dashDeptFilter') ? $('dashDeptFilter').value : '';
  const todayKey = dashboardTodayKeyNow();
  const active = dashboardActiveQuickFilter || { type:'all', value:'' };
  const rows = (dashboardData.requests || []).filter(function(r){
    const hay = [r.requestNo,r.studentName,r.phone,r.department,r.formTitle,r.stage,r.studyType,r.status].join(' ');
    const rowDateKey = dashboardTodayKeyFromValue(r.rawTimestampMs || r.rawTimestamp || r.timestamp);
    const quickOk =
      active.type === 'home' ? false :
      active.type === 'all' || active.type === 'manual' ? true :
      active.type === 'status' ? r.status === active.value :
      active.type === 'department' ? r.department === active.value :
      active.type === 'form' ? r.formTitle === active.value :
      active.type === 'today' ? rowDateKey === todayKey :
      active.type === 'hasFiles' ? Number(r.uploadedFilesCount || 0) > 0 :
      active.type === 'unmatched' ? (r.source === 'upload' && !r.requestNo) || (r.completionNote || '').indexOf('غير موجود') > -1 : true;
    return quickOk && (!q || hay.indexOf(q) > -1) && (!status || r.status === status) && (!form || r.formTitle === form) && (!dept || r.department === dept);
  });
  if ($('dashboardResultTitle')) $('dashboardResultTitle').textContent = dashboardResultLabel() + ' (' + rows.length + ')';
  $('dashboardRows').innerHTML = rows.map(renderDashboardRow).join('') || '<tr><td colspan="9" class="dashboard-empty">لا توجد طلبات مطابقة.</td></tr>';
  qsa('#dashboardRows .dash-done-btn').forEach(function(btn){ btn.addEventListener('click', function(){ dashboardMarkDone(btn.dataset.req); }); });
}
function dashboardFilesHtml(r){
  const raw = Array.isArray(r.files) ? r.files : [];
  const files = raw.filter(function(f){ return f && (f.fileUrl || f.fileId || f.fileName); });
  if (!files.length && r.lastUploadUrl) files.push({ fileUrl:r.lastUploadUrl, fileName:'ملف الدرايف' });
  if (!files.length) return '<span class="muted">لا يوجد</span>';
  if (files.length === 1) {
    const f = files[0];
    return f.fileUrl ? `<a class="drive-link" href="${dashboardEscape(f.fileUrl)}" target="_blank" rel="noopener">فتح الملف</a>` : `<span>${dashboardEscape(f.fileName || 'ملف')}</span>`;
  }
  return `<details class="drive-files"><summary>عرض ${dashboardEscape(files.length)} ملفات</summary>${files.map(function(f, i){
    const label = f.fileName || ('ملف ' + (i+1));
    return f.fileUrl ? `<a href="${dashboardEscape(f.fileUrl)}" target="_blank" rel="noopener">${dashboardEscape(label)}</a>` : `<span>${dashboardEscape(label)}</span>`;
  }).join('')}</details>`;
}
function statusBadge(status){
  const st = String(status || 'جديد');
  let cls = 'new';
  if (st === 'مرفوع') cls = 'uploaded';
  if (st === 'منجز') cls = 'done';
  if (st === 'منجز تلقائيًا') cls = 'auto';
  if (st === 'ناقص') cls = 'missing';
  if (st === 'ملغي') cls = 'cancelled';
  return `<span class="dashboard-status ${cls}">${dashboardEscape(dashboardStatusIcon(st))} ${dashboardEscape(st)}</span>`;
}
function renderDashboardRow(r){
  const phone = r.phone ? `<a class="phone-link" href="tel:${dashboardEscape(r.phone)}">${dashboardEscape(r.phone)}</a>` : '<span class="muted">لا يوجد</span>';
  const files = dashboardFilesHtml(r);
  const canDone = r.status === 'مرفوع' && r.requestNo;
  const action = canDone ? `<button type="button" class="btn primary tiny dash-done-btn" data-req="${dashboardEscape(r.requestNo)}">✅ منجز</button>` : (r.status === 'منجز' || r.status === 'منجز تلقائيًا' ? '<span class="done-inline">تم الإنجاز</span>' : '<span class="muted">—</span>');
  return `<tr>
    <td data-label="الطالب"><strong>${dashboardEscape(r.studentName || 'بدون اسم')}</strong><small>${dashboardEscape(r.timestamp || '')}</small></td>
    <td data-label="رقم الهاتف">${phone}</td>
    <td data-label="القسم"><strong>${dashboardEscape(r.department || 'غير محدد')}</strong></td>
    <td data-label="المرحلة"><strong>${dashboardEscape(r.stage || 'غير محدد')}</strong></td>
    <td data-label="الدراسة">${dashboardEscape(r.studyType || 'غير محدد')}</td>
    <td data-label="الاستمارة"><strong>${dashboardEscape(r.formTitle || 'ملف مرفوع')}</strong><small>${dashboardEscape(r.formCode || '')}</small></td>
    <td data-label="الحالة">${statusBadge(r.status)}</td>
    <td data-label="ملفات الدرايف">${files}</td>
    <td data-label="الإجراء">${action}</td>
  </tr>`;
}
async function dashboardMarkDone(requestNo){
  if (!requestNo) return alert('هذا الطلب غير مربوط برقم طلب في الشيت.');
  const note = prompt('ملاحظة الإنجاز اختيارية:', 'تمت إجراءات التسجيل');
  if (note === null) return;
  try{
    const res = await runServer('dashboardMarkDone', { token:dashboardToken, requestNo:requestNo, note:note });
    dashboardData = res.data;
    dashboardActiveQuickFilter = { type:'status', value:'مرفوع' };
    renderDashboard();
    dashboardSetRefreshText('تم الإنجاز والتحديث الآن');
  }catch(err){ alert(err.message || 'تعذر تحديث الحالة.'); }
}
function clearStaffForm(){
  ['staffOriginalUsername','staffName','staffEmail','staffUsername','staffPassword'].forEach(function(id){ if($(id)) $(id).value=''; });
  if ($('staffRole')) $('staffRole').value = 'staff';
  if ($('staffActive')) $('staffActive').value = 'true';
  if ($('dashboardStaffMsg')) $('dashboardStaffMsg').textContent = '';
  if ($('staffSaveBtn')) $('staffSaveBtn').textContent = 'حفظ';
}
async function openDashboardStaffPanel(){
  if (!dashboardToken || !(dashboardStaff && dashboardStaff.role === 'admin')) return;
  $('dashboardStaffPanel').classList.remove('hidden');
  await dashboardLoadStaff();
}
async function dashboardLoadStaff(){
  try{
    const res = await runServer('dashboardListStaff', { token:dashboardToken });
    $('dashboardStaffList').innerHTML = (res.staff || []).map(function(s){
      return `<div class="staff-row clean-staff-row">
        <div><strong>${dashboardEscape(s.name || s.username)}</strong><span>${dashboardEscape(s.email)} · ${dashboardEscape(s.username)} · ${dashboardEscape(s.role === 'admin' ? 'مدير' : 'موظف')} · ${s.active ? 'فعال' : 'موقوف'}</span></div>
        <div class="staff-actions">
          <button type="button" class="btn ghost tiny dash-staff-edit" data-name="${dashboardEscape(s.name)}" data-email="${dashboardEscape(s.email)}" data-user="${dashboardEscape(s.username)}" data-role="${dashboardEscape(s.role)}" data-active="${s.active ? 'true':'false'}">تعديل</button>
          <button type="button" class="btn ghost tiny dash-staff-toggle" data-user="${dashboardEscape(s.username)}" data-active="${s.active ? '0':'1'}">${s.active ? 'إيقاف':'تفعيل'}</button>
          <button type="button" class="btn danger tiny dash-staff-delete" data-user="${dashboardEscape(s.username)}">حذف</button>
        </div>
      </div>`;
    }).join('') || '<p>لا يوجد موظفون.</p>';
    qsa('.dash-staff-edit').forEach(function(btn){ btn.addEventListener('click', function(){
      $('staffOriginalUsername').value = btn.dataset.user || '';
      $('staffName').value = btn.dataset.name || '';
      $('staffEmail').value = btn.dataset.email || '';
      $('staffUsername').value = btn.dataset.user || '';
      $('staffPassword').value = '';
      $('staffRole').value = btn.dataset.role === 'admin' ? 'admin' : 'staff';
      $('staffActive').value = btn.dataset.active === 'false' ? 'false' : 'true';
      $('staffSaveBtn').textContent = 'تحديث الموظف';
      $('dashboardStaffMsg').textContent = 'يمكنك تعديل اليوزر أو كلمة المرور. اترك كلمة المرور فارغة إذا لا تريد تغييرها.';
    }); });
    qsa('.dash-staff-toggle').forEach(function(btn){ btn.addEventListener('click', async function(){
      await runServer('dashboardToggleStaff', { token:dashboardToken, username:btn.dataset.user, active:btn.dataset.active === '1' });
      await dashboardLoadStaff();
    }); });
    qsa('.dash-staff-delete').forEach(function(btn){ btn.addEventListener('click', async function(){
      if (!confirm('تأكيد حذف الموظف: ' + btn.dataset.user + ' ؟')) return;
      await runServer('dashboardDeleteStaff', { token:dashboardToken, username:btn.dataset.user });
      clearStaffForm();
      await dashboardLoadStaff();
    }); });
  }catch(err){ $('dashboardStaffMsg').textContent = err.message || 'تعذر تحميل الموظفين.'; }
}
async function dashboardAddStaffSubmit(e){
  e.preventDefault();
  try{
    const staff = {
      originalUsername:$('staffOriginalUsername').value.trim(),
      name:$('staffName').value.trim(),
      email:$('staffEmail').value.trim(),
      username:$('staffUsername').value.trim(),
      password:$('staffPassword').value,
      role:$('staffRole').value,
      active:$('staffActive').value === 'true'
    };
    await runServer('dashboardSaveStaff', { token:dashboardToken, staff:staff });
    clearStaffForm();
    $('dashboardStaffMsg').textContent = 'تم حفظ بيانات الموظف.';
    await dashboardLoadStaff();
  }catch(err){ $('dashboardStaffMsg').textContent = err.message || 'تعذر حفظ بيانات الموظف.'; }
}


/* =======================
   Dashboard v9 fixes
   ======================= */
function dashboardSetModeV9(){
  const modal = $('dashboardModal');
  if (!modal) return;
  const active = dashboardActiveQuickFilter || { type:'home', value:'' };
  const isHome = active.type === 'home';
  modal.classList.toggle('cards-mode', isHome);
  modal.classList.toggle('results-mode', !isHome);
  qsa('#dashboardModal .cards-only-section').forEach(function(section){ section.classList.toggle('hidden', !isHome); });
  const hint = $('dashboardHomeHint');
  if (hint) hint.classList.toggle('hidden', !isHome);
  const results = $('dashboardResultsAnchor');
  if (results) results.classList.toggle('hidden', isHome);
}
function dashboardActivateCard(type, value){
  dashboardActiveQuickFilter = { type:type || 'all', value:value || '' };
  if ($('dashSearch')) $('dashSearch').value = '';
  if ($('dashStatusFilter')) $('dashStatusFilter').value = '';
  if ($('dashFormFilter')) $('dashFormFilter').value = '';
  if ($('dashDeptFilter')) $('dashDeptFilter').value = '';
  if (type === 'status' && $('dashStatusFilter')) $('dashStatusFilter').value = value || '';
  if (type === 'department' && $('dashDeptFilter')) $('dashDeptFilter').value = value || '';
  if (type === 'form' && $('dashFormFilter')) $('dashFormFilter').value = value || '';
  renderDashboard();
  if (type !== 'home') dashboardScrollToResults();
}
function renderDashboard(){
  if (!dashboardData) return;
  const s = dashboardData.stats || {};
  if ($('dashboardUserBox')) $('dashboardUserBox').innerHTML = `<strong>${dashboardEscape(dashboardStaff && dashboardStaff.name || 'موظف')}</strong><span>${dashboardEscape(dashboardStaff && dashboardStaff.role === 'admin' ? 'مدير' : 'موظف')}</span>`;
  if ($('dashboardStaffBtn')) $('dashboardStaffBtn').style.display = dashboardStaff && dashboardStaff.role === 'admin' ? '' : 'none';
  const stats = [
    { label:'كل الطلبات', count:s.total || 0, icon:'📋', type:'all', tone:'tone-blue' },
    { label:'جديدة', count:s.newCount || 0, icon:'🕘', type:'status', value:'جديد', tone:'tone-slate' },
    { label:'مرفوعة', count:s.uploaded || 0, icon:'⬆️', type:'status', value:'مرفوع', tone:'tone-amber' },
    { label:'منجزة', count:s.completed || 0, icon:'✅', type:'status', value:'منجز', tone:'tone-green' },
    { label:'فحص ومعالجة تلقائي', count:s.autoCompleted || 0, icon:'🩺', type:'status', value:'منجز تلقائيًا', tone:'tone-cyan' },
    { label:'ملفات الدرايف', count:s.uploadedTotal || 0, icon:'📁', type:'hasFiles', tone:'tone-violet' },
    { label:'غير مربوطة', count:s.unmatchedUploads || 0, icon:'🔗', type:'unmatched', tone:'tone-red' },
    { label:'طلبات اليوم', count:s.today || 0, icon:'📅', type:'today', tone:'tone-teal' }
  ];
  if ($('dashboardStats')) $('dashboardStats').innerHTML = stats.map(dashboardStatCard).join('');
  renderDepartmentCards('dashByDepartment', s.byDepartment || []);
  dashboardFillSelect('dashStatusFilter', (s.byStatus || []).map(function(x){ return x.name; }), 'كل الحالات');
  dashboardFillSelect('dashFormFilter', (s.byForm || []).map(function(x){ return x.name; }), 'كل الاستمارات');
  dashboardFillSelect('dashDeptFilter', (typeof departments !== 'undefined' ? departments : (s.byDepartment || []).map(function(x){ return x.name; })), 'كل الأقسام');
  qsa('#dashboardModal .dash-click-card').forEach(function(btn){ btn.addEventListener('click', function(){ dashboardActivateCard(btn.dataset.filterType || 'all', btn.dataset.filterValue || ''); }); });
  dashboardSetModeV9();
  if ((dashboardActiveQuickFilter || {}).type !== 'home') dashboardApplyFilters();
}
function dashboardApplyFilters(){
  if (!dashboardData || !$('dashboardRows')) return;
  const q = ($('dashSearch') && $('dashSearch').value || '').trim();
  const status = $('dashStatusFilter') ? $('dashStatusFilter').value : '';
  const form = $('dashFormFilter') ? $('dashFormFilter').value : '';
  const dept = $('dashDeptFilter') ? $('dashDeptFilter').value : '';
  const todayKey = dashboardTodayKeyNow();
  const active = dashboardActiveQuickFilter || { type:'all', value:'' };
  dashboardSetModeV9();
  const rows = (dashboardData.requests || []).filter(function(r){
    const hay = [r.requestNo,r.studentName,r.phone,r.department,r.formTitle,r.stage,r.studyType,r.status].join(' ');
    const rowDateKey = dashboardTodayKeyFromValue(r.rawTimestampMs || r.rawTimestamp || r.timestamp);
    const quickOk = active.type === 'home' ? false : active.type === 'all' || active.type === 'manual' ? true : active.type === 'status' ? r.status === active.value : active.type === 'department' ? r.department === active.value : active.type === 'form' ? r.formTitle === active.value : active.type === 'today' ? rowDateKey === todayKey : active.type === 'hasFiles' ? Number(r.uploadedFilesCount || 0) > 0 : active.type === 'unmatched' ? (r.source === 'upload' || !r.requestNo || (r.completionNote || '').indexOf('غير موجود') > -1 || (r.completionNote || '').indexOf('غير مربوط') > -1) : true;
    return quickOk && (!q || hay.indexOf(q) > -1) && (!status || r.status === status) && (!form || r.formTitle === form) && (!dept || r.department === dept);
  });
  if ($('dashboardResultTitle')) $('dashboardResultTitle').textContent = dashboardResultLabel() + ' (' + rows.length + ')';
  $('dashboardRows').innerHTML = rows.map(renderDashboardRow).join('') || '<tr><td colspan="9" class="dashboard-empty">لا توجد طلبات مطابقة.</td></tr>';
  qsa('#dashboardRows .dash-done-btn').forEach(function(btn){ btn.addEventListener('click', function(){ dashboardMarkDone(btn.dataset.req); }); });
}
function renderDashboardRow(r){
  const phone = r.phone ? `<a class="phone-link" href="tel:${dashboardEscape(r.phone)}">${dashboardEscape(r.phone)}</a>` : '<span class="muted">لا يوجد</span>';
  const files = dashboardFilesHtml(r);
  const isLinkedRequest = r.source === 'request' && !!r.requestNo;
  const canDone = isLinkedRequest && r.status === 'مرفوع';
  let action = '<span class="muted">—</span>';
  if (canDone) action = `<button type="button" class="btn danger tiny dash-done-btn" data-req="${dashboardEscape(r.requestNo)}" title="اضغط لتحويل الطلب إلى منجز">غير منجز</button>`;
  else if (r.status === 'منجز' || r.status === 'منجز تلقائيًا') action = '<span class="done-inline">منجز</span>';
  else if (r.source === 'upload') action = '<span class="unlinked-inline">غير مربوط</span>';
  return `<tr>
    <td data-label="الطالب"><strong>${dashboardEscape(r.studentName || 'بدون اسم')}</strong><small>${dashboardEscape(r.timestamp || '')}</small></td>
    <td data-label="رقم الهاتف">${phone}</td>
    <td data-label="القسم"><strong>${dashboardEscape(r.department || 'غير محدد')}</strong></td>
    <td data-label="المرحلة"><strong>${dashboardEscape(r.stage || 'غير محدد')}</strong></td>
    <td data-label="الدراسة">${dashboardEscape(r.studyType || 'غير محدد')}</td>
    <td data-label="الاستمارة"><strong>${dashboardEscape(r.formTitle || 'ملف مرفوع')}</strong><small>${dashboardEscape(r.formCode || '')}</small></td>
    <td data-label="الحالة">${statusBadge(r.status)}</td>
    <td data-label="ملفات الدرايف">${files}</td>
    <td data-label="الإجراء">${action}</td>
  </tr>`;
}
async function dashboardMarkDone(requestNo){
  if (!requestNo) return alert('هذا الملف غير مربوط بطلب داخل صفحة Requests، لذلك لا يمكن إنجازه من هنا.');
  if (!confirm('هل تريد تحويل هذا الطلب إلى منجز؟')) return;
  try{
    const res = await runServer('dashboardMarkDone', { token:dashboardToken, requestNo:requestNo, note:'تمت إجراءات التسجيل' });
    dashboardData = res.data;
    dashboardActiveQuickFilter = { type:'status', value:'مرفوع' };
    renderDashboard();
    dashboardSetRefreshText('تم الإنجاز والتحديث الآن');
  }catch(err){ alert(err.message || 'تعذر تحديث الحالة.'); }
}


/* =======================
   Dashboard v10 corrections
   ======================= */
function setupDashboardUI(){
  const hero = document.querySelector('.hero-actions');
  if (hero && !$('dashboardOpenBtn')) {
    const btn = document.createElement('button');
    btn.id = 'dashboardOpenBtn';
    btn.type = 'button';
    btn.className = 'btn dashboard-entry-btn';
    btn.textContent = 'لوحة المتابعة';
    btn.addEventListener('click', openDashboardLogin);
    hero.appendChild(btn);
  }
  /* مهم: لا نضيف حقول ولا نغيّر صفحة الرفع أو الاستمارات هنا. */
}
function openDashboardLogin(){
  ensureDashboardModal();
  const modal = $('dashboardModal');
  if (!modal) return;
  modal.classList.remove('hidden');
  document.body.classList.add('dashboard-open-lock');
  document.documentElement.classList.add('dashboard-open-lock');
  if (dashboardToken && dashboardData) showDashboardApp(); else showDashboardLogin();
}
function closeDashboardModal(){
  dashboardStopAutoRefresh();
  const modal = $('dashboardModal');
  if (modal) modal.classList.add('hidden');
  document.body.classList.remove('dashboard-open-lock');
  document.documentElement.classList.remove('dashboard-open-lock');
}
function dashboardScrollToResults(){
  const target = $('dashboardResultsAnchor');
  if (target && target.scrollIntoView) setTimeout(function(){ target.scrollIntoView({ behavior:'smooth', block:'start' }); }, 30);
}
function dashboardSetModeV10(){
  const modal = $('dashboardModal');
  if (!modal) return;
  const active = dashboardActiveQuickFilter || { type:'home', value:'' };
  const isHome = active.type === 'home';
  modal.classList.toggle('cards-mode', isHome);
  modal.classList.toggle('results-mode', !isHome);
  qsa('#dashboardModal .cards-only-section').forEach(function(section){ section.classList.toggle('hidden', !isHome); });
  const hint = $('dashboardHomeHint');
  if (hint) hint.classList.toggle('hidden', !isHome);
  const results = $('dashboardResultsAnchor');
  if (results) results.classList.toggle('hidden', isHome);
}
function dashboardStatusIcon(status){
  const st = String(status || '');
  if (st === 'مرفوع') return '⬆️';
  if (st === 'منجز') return '✅';
  if (st === 'منجز تلقائيًا') return '🤖';
  if (st === 'جديد') return '🕘';
  if (st === 'ناقص') return '⚠️';
  if (st === 'ملغي') return '🚫';
  if (st.indexOf('غير مربوط') > -1) return '🔗';
  return '📋';
}
function renderDashboard(){
  if (!dashboardData) return;
  const s = dashboardData.stats || {};
  if ($('dashboardUserBox')) $('dashboardUserBox').innerHTML = `<strong>${dashboardEscape(dashboardStaff && dashboardStaff.name || 'موظف')}</strong><span>${dashboardEscape(dashboardStaff && dashboardStaff.role === 'admin' ? 'مدير' : 'موظف')}</span>`;
  if ($('dashboardStaffBtn')) $('dashboardStaffBtn').style.display = dashboardStaff && dashboardStaff.role === 'admin' ? '' : 'none';
  const stats = [
    { label:'كل الطلبات', count:s.total || 0, icon:'📋', type:'all', tone:'tone-blue' },
    { label:'جديدة', count:s.newCount || 0, icon:'🕘', type:'status', value:'جديد', tone:'tone-slate' },
    { label:'مرفوعة / غير منجزة', count:s.uploaded || 0, icon:'⬆️', type:'status', value:'مرفوع', tone:'tone-red' },
    { label:'منجزة', count:s.completed || 0, icon:'✅', type:'status', value:'منجز', tone:'tone-green' },
    { label:'فحص ومعالجة تلقائي', count:s.autoCompleted || 0, icon:'🩺', type:'status', value:'منجز تلقائيًا', tone:'tone-cyan' },
    { label:'ملفات الدرايف', count:s.uploadedTotal || 0, icon:'📁', type:'hasFiles', tone:'tone-violet' },
    { label:'غير مربوطة', count:s.unmatchedUploads || 0, icon:'🔗', type:'unmatched', tone:'tone-amber' },
    { label:'طلبات اليوم', count:s.today || 0, icon:'📅', type:'today', tone:'tone-teal' }
  ];
  if ($('dashboardStats')) $('dashboardStats').innerHTML = stats.map(dashboardStatCard).join('');
  renderDepartmentCards('dashByDepartment', s.byDepartment || []);
  dashboardFillSelect('dashStatusFilter', (s.byStatus || []).map(function(x){ return x.name; }), 'كل الحالات');
  dashboardFillSelect('dashFormFilter', (s.byForm || []).map(function(x){ return x.name; }), 'كل الاستمارات');
  dashboardFillSelect('dashDeptFilter', (typeof departments !== 'undefined' ? departments : (s.byDepartment || []).map(function(x){ return x.name; })), 'كل الأقسام');
  qsa('#dashboardModal .dash-click-card').forEach(function(btn){ btn.addEventListener('click', function(){ dashboardActivateCard(btn.dataset.filterType || 'all', btn.dataset.filterValue || ''); }); });
  dashboardSetModeV10();
  if ((dashboardActiveQuickFilter || {}).type !== 'home') dashboardApplyFilters();
}
function dashboardApplyFilters(){
  if (!dashboardData || !$('dashboardRows')) return;
  const q = ($('dashSearch') && $('dashSearch').value || '').trim();
  const status = $('dashStatusFilter') ? $('dashStatusFilter').value : '';
  const form = $('dashFormFilter') ? $('dashFormFilter').value : '';
  const dept = $('dashDeptFilter') ? $('dashDeptFilter').value : '';
  const todayKey = dashboardTodayKeyNow();
  const active = dashboardActiveQuickFilter || { type:'all', value:'' };
  dashboardSetModeV10();
  const rows = (dashboardData.requests || []).filter(function(r){
    const hay = [r.requestNo,r.studentName,r.phone,r.department,r.formTitle,r.stage,r.studyType,r.status].join(' ');
    const rowDateKey = dashboardTodayKeyFromValue(r.rawTimestampMs || r.rawTimestamp || r.timestamp);
    const quickOk = active.type === 'home' ? false : active.type === 'all' || active.type === 'manual' ? true : active.type === 'status' ? r.status === active.value : active.type === 'department' ? r.department === active.value : active.type === 'form' ? r.formTitle === active.value : active.type === 'today' ? rowDateKey === todayKey : active.type === 'hasFiles' ? Number(r.uploadedFilesCount || 0) > 0 : active.type === 'unmatched' ? (r.source === 'upload' && (!r.requestNo || (r.completionNote || '').indexOf('Requests') > -1)) : true;
    return quickOk && (!q || hay.indexOf(q) > -1) && (!status || r.status === status) && (!form || r.formTitle === form) && (!dept || r.department === dept);
  });
  if ($('dashboardResultTitle')) $('dashboardResultTitle').textContent = dashboardResultLabel() + ' (' + rows.length + ')';
  $('dashboardRows').innerHTML = rows.map(renderDashboardRow).join('') || '<tr><td colspan="9" class="dashboard-empty">لا توجد طلبات مطابقة.</td></tr>';
  qsa('#dashboardRows .dash-done-btn').forEach(function(btn){ btn.addEventListener('click', function(){ dashboardMarkDoneFromButton(btn); }); });
}
function renderDashboardRow(r){
  const phone = r.phone ? `<a class="phone-link" href="tel:${dashboardEscape(r.phone)}">${dashboardEscape(r.phone)}</a>` : '<span class="muted">لا يوجد</span>';
  const files = dashboardFilesHtml(r);
  const canDone = r.status === 'مرفوع' && (r.requestNo || r.uploadRow || r.actionKey);
  let action = '<span class="muted">—</span>';
  if (canDone) action = `<button type="button" class="btn danger tiny dash-done-btn" data-target="${dashboardEscape(r.actionTarget || (r.source === 'upload' ? 'upload' : 'request'))}" data-req="${dashboardEscape(r.requestNo || '')}" data-upload-row="${dashboardEscape(r.uploadRow || '')}" title="اضغط بعد إكمال إجراءات التسجيل">غير منجز</button>`;
  else if (r.status === 'منجز' || r.status === 'منجز تلقائيًا') action = '<span class="done-inline">منجز</span>';
  return `<tr>
    <td data-label="الطالب"><strong>${dashboardEscape(r.studentName || 'بدون اسم')}</strong><small>${dashboardEscape(r.timestamp || '')}</small></td>
    <td data-label="رقم الهاتف">${phone}</td>
    <td data-label="القسم"><strong>${dashboardEscape(r.department || 'غير محدد')}</strong></td>
    <td data-label="المرحلة"><strong>${dashboardEscape(r.stage || 'غير محدد')}</strong></td>
    <td data-label="الدراسة">${dashboardEscape(r.studyType || 'غير محدد')}</td>
    <td data-label="الاستمارة"><strong>${dashboardEscape(r.formTitle || 'ملف مرفوع')}</strong><small>${dashboardEscape(r.formCode || '')}</small></td>
    <td data-label="الحالة">${statusBadge(r.status)}</td>
    <td data-label="ملفات الدرايف">${files}</td>
    <td data-label="الإجراء">${action}</td>
  </tr>`;
}
async function dashboardMarkDoneFromButton(btn){
  if (!btn) return;
  await dashboardMarkDone(btn.dataset.req || '', btn.dataset.uploadRow || '', btn.dataset.target || '');
}
async function dashboardMarkDone(requestNo, uploadRow, target){
  if (!requestNo && !uploadRow) return alert('لا يوجد طلب أو ملف محدد للتحديث في Google Sheets.');
  if (!confirm('هل أكملت إجراءات هذا الطلب وتريد تحويله إلى منجز؟')) return;
  try{
    const res = await runServer('dashboardMarkDone', { token:dashboardToken, requestNo:requestNo || '', uploadRow:uploadRow || '', target:target || '', note:'تمت إجراءات التسجيل' });
    dashboardData = res.data;
    dashboardActiveQuickFilter = { type:'status', value:'مرفوع' };
    renderDashboard();
    dashboardSetRefreshText('تم الإنجاز والتحديث الآن');
  }catch(err){ alert(err.message || 'تعذر تحديث الحالة في Google Sheets.'); }
}


/* =======================
   Dashboard v11 fixes
   - أسرع بالفتح: الدخول لا ينتظر بناء الجداول، والبيانات تُحمّل بعد ظهور اللوحة.
   - استبدال رسائل confirm/alert الخاصة بالإنجاز بنافذة داخل النظام بدون نص embedded page.
   - توقيع النظام وصورة صغيرة في صفحة الإعدادات.
   ======================= */
const DASHBOARD_DEV_AVATAR_V11 = '';// avatar disabled to avoid long inline JS token
const DASHBOARD_DEV_NAME_V11 = 'Aymen Mohammed Jebur';
const ensureDashboardModalV10Ref = ensureDashboardModal;
function ensureDashboardModal(){
  ensureDashboardModalV10Ref();
  dashboardApplyV11Chrome();
}
function dashboardApplyV11Chrome(){
  const hint = $('dashboardHomeHint');
  if (hint) {
    hint.className = 'dashboard-home-hint dashboard-system-credit';
    hint.innerHTML = (DASHBOARD_DEV_AVATAR_V11 ? '<img class="dev-mark" src="' + DASHBOARD_DEV_AVATAR_V11 + '" alt="Aymen Mohammed Jebur">' : '') + '<span>Designed and Developed by</span><bdi dir="ltr">' + dashboardEscape(DASHBOARD_DEV_NAME_V11) + '</bdi>';
  }
  const staffPanel = $('dashboardStaffPanel');
  if (staffPanel && !$('dashboardDeveloperMini')) {
    const panelHead = staffPanel.querySelector('.dashboard-panel-head');
    const dev = document.createElement('div');
    dev.id = 'dashboardDeveloperMini';
    dev.className = 'dashboard-developer-mini';
    dev.innerHTML = (DASHBOARD_DEV_AVATAR_V11 ? '<img src="' + DASHBOARD_DEV_AVATAR_V11 + '" alt="Developer">' : '') + (DASHBOARD_DEV_AVATAR_V11 ? '<img class="dev-mark" src="' + DASHBOARD_DEV_AVATAR_V11 + '" alt="Aymen Mohammed Jebur">' : '') + '<span>Designed and Developed by</span><bdi dir="ltr">' + dashboardEscape(DASHBOARD_DEV_NAME_V11) + '</bdi>';
    if (panelHead) panelHead.insertAdjacentElement('afterend', dev);
  }
  if (!$('dashboardConfirmLayer')) {
    const layer = document.createElement('div');
    layer.id = 'dashboardConfirmLayer';
    layer.className = 'dashboard-confirm-layer hidden';
    layer.innerHTML = '<div class="dashboard-confirm-card"><h3 id="dashboardConfirmTitle">تأكيد الإجراء</h3><p id="dashboardConfirmText"></p><div class="dashboard-confirm-actions"><button type="button" class="btn danger" id="dashboardConfirmYes">تأكيد الإنجاز</button><button type="button" class="btn ghost" id="dashboardConfirmNo">إلغاء</button></div></div>';
    const shell = document.querySelector('#dashboardModal .dashboard-shell') || $('dashboardModal') || document.body;
    shell.appendChild(layer);
  }
  if (!$('dashboardToast')) {
    const toast = document.createElement('div');
    toast.id = 'dashboardToast';
    toast.className = 'dashboard-toast hidden';
    const shell = document.querySelector('#dashboardModal .dashboard-shell') || $('dashboardModal') || document.body;
    shell.appendChild(toast);
  }
}
function dashboardToastV11(message, type){
  const el = $('dashboardToast');
  if (!el) return;
  el.textContent = message || '';
  el.className = 'dashboard-toast ' + (type || 'ok');
  clearTimeout(el._t);
  el._t = setTimeout(function(){ el.classList.add('hidden'); }, 2800);
}
function dashboardConfirmV11(message){
  dashboardApplyV11Chrome();
  return new Promise(function(resolve){
    const layer = $('dashboardConfirmLayer');
    const text = $('dashboardConfirmText');
    const yes = $('dashboardConfirmYes');
    const no = $('dashboardConfirmNo');
    if (!layer || !yes || !no) { resolve(window.confirm(message)); return; }
    if (text) text.textContent = message || 'هل تريد تنفيذ هذا الإجراء؟';
    layer.classList.remove('hidden');
    function cleanup(value){
      layer.classList.add('hidden');
      yes.removeEventListener('click', onYes);
      no.removeEventListener('click', onNo);
      layer.removeEventListener('click', onLayer);
      document.removeEventListener('keydown', onKey);
      resolve(value);
    }
    function onYes(){ cleanup(true); }
    function onNo(){ cleanup(false); }
    function onLayer(e){ if (e.target === layer) cleanup(false); }
    function onKey(e){ if (e.key === 'Escape') cleanup(false); }
    yes.addEventListener('click', onYes);
    no.addEventListener('click', onNo);
    layer.addEventListener('click', onLayer);
    document.addEventListener('keydown', onKey);
  });
}
function dashboardRenderLoadingV11(){
  dashboardApplyV11Chrome();
  if ($('dashboardStats')) $('dashboardStats').innerHTML = Array.from({length:8}).map(function(_,i){ return '<div class="dashboard-stat-card skeleton-card"><span></span><strong></strong><em></em></div>'; }).join('');
  if ($('dashByDepartment')) $('dashByDepartment').innerHTML = Array.from({length:7}).map(function(_,i){ return '<div class="dept-card skeleton-card"><span></span><strong></strong><em></em></div>'; }).join('');
  if ($('dashboardHomeHint')) $('dashboardHomeHint').classList.remove('hidden');
  if ($('dashboardResultsAnchor')) $('dashboardResultsAnchor').classList.add('hidden');
}
function showDashboardApp(){
  const modal = $('dashboardModal');
  if (modal) { modal.classList.remove('login-mode'); modal.classList.add('app-mode'); }
  const login = $('dashboardLoginView');
  const app = $('dashboardAppView');
  if (login) { login.classList.add('hidden'); login.style.display = 'none'; }
  if (app) { app.classList.remove('hidden'); app.style.display = 'block'; }
  dashboardApplyV11Chrome();
  if (dashboardData) {
    try { renderDashboard(); } catch (err) { dashboardToastV11('تم الدخول لكن تعذر عرض البيانات.', 'bad'); }
  } else {
    dashboardRenderLoadingV11();
    dashboardSetRefreshText('جاري تحميل البيانات...');
  }
  dashboardStartAutoRefresh();
}
async function dashboardLoginSubmit(e){
  if (e) e.preventDefault();
  const msg = $('dashboardLoginMsg');
  if (msg) msg.textContent = 'جاري التحقق...';
  try{
    const username = ($('dashUsername') && $('dashUsername').value || '').trim();
    const password = ($('dashPassword') && $('dashPassword').value || '');
    const res = await runServer('dashboardLogin', { username:username, password:password });
    dashboardToken = res.token || '';
    dashboardStaff = res.staff || null;
    dashboardData = res.data || null;
    if (!dashboardToken) throw new Error('تم قبول البيانات لكن لم يصل رمز الدخول من الخادم. أعد النشر ثم جرّب.');
    if (msg) msg.textContent = '';
    dashboardActiveQuickFilter = { type:'home', value:'' };
    showDashboardApp();
    if (!dashboardData) dashboardRefresh(false);
  }catch(err){
    if (msg) msg.textContent = err && err.message ? err.message : 'تعذر الدخول.';
  }
}
function dashboardStartAutoRefresh(){
  dashboardStopAutoRefresh();
  dashboardAutoRefreshTimer = setInterval(function(){ dashboardRefresh(true); }, 60000);
}
async function dashboardRefresh(silent){
  if (!dashboardToken || dashboardSilentRefresh) return;
  dashboardSilentRefresh = true;
  const btn = $('dashboardRefreshBtn');
  if (btn && !silent) btn.disabled = true;
  dashboardSetRefreshText(silent ? 'تحديث تلقائي خفيف...' : 'جاري التحديث...');
  try{
    const res = await runServer('dashboardGetData', { token: dashboardToken });
    dashboardData = res.data;
    if (!dashboardData) throw new Error('لم تصل بيانات اللوحة من الخادم.');
    renderDashboard();
    dashboardSetRefreshText('آخر تحديث: ' + new Date().toLocaleTimeString('ar-IQ'));
  }catch(err){
    dashboardSetRefreshText('تعذر التحديث');
    if (!silent) dashboardToastV11(err.message || 'تعذر تحديث البيانات.', 'bad');
  } finally {
    dashboardSilentRefresh = false;
    if (btn) btn.disabled = false;
  }
}
